export declare const VirtualMachinesRules = "\n# Virtual Machines - WAF Rules for IaC\n\n- Deploy VMs across multiple availability zones\n- Use managed disks with appropriate redundancy (LRS, ZRS)\n- Configure appropriate VM size and series for workload\n- Use managed identities for service authentication\n- Configure network security groups with minimal access\n- Enable disk encryption at rest\n- Enable secure boot and trusted launch for supported VMs\n- Configure accelerated networking for network-intensive workloads\n- Configure proximity placement groups for low-latency requirements\n- Enable boot diagnostics and VM diagnostics\n- Enable diagnostic logging to Log Analytics workspace\n- Configure auto-shutdown schedules for cost savings\n";
